async getTokens(blockchain?: string): Promise<RangoToken[]> {
  const params = new URLSearchParams()
  if (blockchain) {
    params.append('blockchain', blockchain)
  }

  const data = await this.request<{ tokens: RangoToken[] }>(`/basic/meta?${params}`)
  return data.tokens
}

